# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class Player : MonoBehaviour
{
    public int health = 100;
    public int currency = 500;
    public int damage = 10;

    public void TakeDamage(int damageAmount)
    {
        health -= damageAmount;
        if (health < 0) health = 0;
    }

    public void Heal(int healAmount)
    {
        health += healAmount;
        if (health > 100) health = 100; // Assuming 100 is max health
    }

    public void EarnCurrency(int amount)
    {
        currency += amount;
    }

    public bool PurchaseItem(int price)
    {
        if (currency >= price)
        {
            currency -= price;
            return true;
        }
        return false;
    }

    public int CalculatePrice(int basePrice, int increaseFactor)
    {
        return basePrice + (increaseFactor * basePrice) / 100;
    }

    public int CalculateDamage(int baseDamage, int powerUp)
    {
        return baseDamage + powerUp;
    }
}

public class Shop : MonoBehaviour
{
    public Player player;

    public void PurchaseHealthPotion(int basePrice, int increaseFactor)
    {
        int price = player.CalculatePrice(basePrice, increaseFactor);
        if (player.PurchaseItem(price))
        {
            player.Heal(20);
            Debug.Log("Health Potion Purchased!");
        }
        else
        {
            Debug.Log("Not enough currency!");
        }
    }

    public void PurchaseDamageUpgrade(int basePrice, int increaseFactor, int powerUp)
    {
        int price = player.CalculatePrice(basePrice, increaseFactor);
        if (player.PurchaseItem(price))
        {
            player.damage = player.CalculateDamage(player.damage, powerUp);
            Debug.Log("Damage Upgrade Purchased!");
        }
        else
        {
            Debug.Log("Not enough currency!");
        }
    }
}